import{_ as t,c as r,o as e,a}from"./app.015fbf38.js";const m='{"title":"Nokia \u820A\u65E5\u60C5\u612B\u3001\u65B0\u667A\u6167\u578B\u624B\u6A5F","description":"","frontmatter":{"title":"Nokia \u820A\u65E5\u60C5\u612B\u3001\u65B0\u667A\u6167\u578B\u624B\u6A5F","date":"2018-05-25T02:36:58.000Z","categories":["\u751F\u6D3B\u8A18\u4E8B"]},"headers":[],"relativePath":"Bike/BikeTravel/20180525_Nokia_\u820A\u65E5\u60C5\u612B\u3001\u65B0\u667A\u6167\u578B\u624B\u6A5F.md","lastUpdated":1648513476165}',o={},i=a('<p><a href="https://www.nokia.com/zh_tw/phones/nokia-6" target="_blank"><img src="https://farm2.staticflickr.com/1745/41675726324_390ff529da_k.jpg"></a></p><p>\u5927\u7D04\u5169\u9031\u524D\uFF0C\u539F\u672C\u7684\u624B\u6A5F(HTC M8)<br> \u53F3\u534A\u90E8\u4E5F\u51FA\u73FE\u6309\u9375\u4E0D\u9748\u654F\u7684\u60C5\u6CC1<br> \u5F88\u6709\u53EF\u80FD\u9A0E\u8ECA\u8DEF\u9762\u985B\u7C38\u9707\u58DE\u7684<br></p><p><span style="color:red;">\u4EE5\u4E0B\u5716\u7247\u63A1\u81EA<a href="https://www.nokia.com/zh_tw/phones/nokia-6">Nokia\u5B98\u65B9\u7DB2\u7AD9</a></span></p><p>\u53BB\u5E74\u56DE\u5357\u90E8\u524D\uFF0C\u624B\u6A5F\u5DF2\u7D93\u7528\u4E86\u5169\u5E74\u7121\u5927\u7919<br> \u516B\u6708\u7684\u6642\u5019\u6709\u63DB\u904E\u96FB\u6C60\uFF0C\u90A3\u6642\u89BA\u5F97\u624B\u6A5F\u9084\u80FD\u7528\u4E00\u9663\u5B50<br> \u63A5\u8FD1\u5E74\u5E95\u6642\uFF0C\u76F8\u6A5F\u958B\u59CB\u7121\u6CD5\u5C0D\u7126(\u7DB2\u8DEF\u4E0A\u8AAA\u6709OIS\u5F88\u5BB9\u6613\u9019\u6A23)<br> \u9694\u4E00\u9663\u5B50\u63DB\u5DE6\u534A\u90E8\u7D04\u4E00\u516C\u5206\u5BEC\uFF0C\u89F8\u63A7\u6C92\u53CD\u61C9<br> \u6211\u89BA\u5F97\u6709\u53EF\u80FD\u63DB\u516C\u8DEF\u8ECA\uFF0C\u8DEF\u6CC1\u6703\u76F4\u63A5\u50B3\u905E\u4E0A\u4F86<br> \u4E0A\u73ED\u6709\u5E7E\u6BB5\u8DEF\u5F88\u7CDF\uFF0C\u8DEF\u9762\u4E0D\u5E73\u5230\u6703\u89BA\u5F97\u50CF\u5728\u5750\u6D77\u76DC\u8239</p><p>\u4E0A\u9031\u958B\u59CB\u627E\u5C0B\u8F03\u5408\u9069\u7684\u624B\u6A5F\uFF0C\u5E0C\u671B\u80FD\u5118\u5FEB\u66F4\u63DB<br> \u5206\u6790\u4E86\u4E00\u4E0B\u76EE\u524D\u7684\u9700\u6C42\uFF0C\u5176\u5BE6\u73FE\u5728\u7684\u4F7F\u7528\u5EA6\u5F88\u4F4E<br> \u56E0\u70BA\u624B\u6A5F\u7684\u5149\u5708\u4E0D\u80FD\u8ABF\uFF0C\u73FE\u5728\u5927\u591A\u7528\u76F8\u6A5F\u62CD\u7167<br> \u5217\u4E86\u5E7E\u9EDE\u5982\u4E0B\uFF1A<br> 1.\u624B\u6A5F\u4E0D\u8981\u592A\u5927\uFF0C\u5118\u91CF5.5\u540B\u5DE6\u53F3<br> \u9A0E\u8ECA\u6211\u6703\u7D81\u5728\u9F8D\u982D\u65B9\u4FBF\u627E\u5730\u5716\uFF0C\u592A\u5927\u53EF\u80FD\u4E0D\u597D\u7D81<br> \u53E6\u5916\uFF0C\u592A\u5927\u4E5F\u53EF\u80FD\u6703\u5361\u5230\u55AE\u8ECA\u7684\u78BC\u8868</p><p>2.\u5118\u91CF\u662F\u92C1\u5408\u91D1\uFF0C\u53EF\u4EE5\u8010\u6454\u3001\u8010\u7528<br> \u56E0\u70BA\u9A0E\u8ECA\u7684\u95DC\u4FC2\uFF0C\u8003\u91CF\u6709\u53EF\u80FD\u6703\u9047\u5230\u96AA\u60E1\u74B0\u5883<br> \u64D4\u5FC3\u5982\u679C\u624B\u6A5F\u6C92\u7D81\u597D\uFF0C\u53EF\u80FD\u4E0D\u5C0F\u5FC3\u6703\u6454\u5230\u5730\u4E0A<br> \u5E0C\u671B\u80FD\u5920\u662F\u92C1\u5408\u91D1\u7684\u6750\u8CEA\uFF0C\u6BD4\u8F03\u4E0D\u6015\u6454<br><img src="https://images.ctfassets.net/wcfotm6rrl7u/m9wbLaAYASKeKiEiCQOM2/51953a0e289fbe5a21f2093e3ca98620/nokia_6_1-video_thumbnail-campaign.jpg" alt=""></p><p>3.\u4E0D\u8981\u662F\u5927\u9678\u7684\u724C\u5B50<br> \u6709\u4EBA\u8AAA\u5C0F\u7C73\u7684\u624B\u6A5F\u5F88\u4FBF\u5B9C\uFF0C\u6216\u83EF\u70BA\u7684\u62CD\u7167\u529F\u80FD\u5F88\u5F37<br> \u56E0\u70BA\u5927\u9678\u624B\u6A5F\u4E4B\u524D\u6709\u500B\u8CC7\u56DE\u50B3\u81F3\u5927\u9678\u8CC7\u6599\u4E2D\u5FC3\u554F\u984C<br> \u6240\u4EE5\u5118\u91CF\u907F\u958B\u662F\u5927\u9678\u624B\u6A5F\uFF0C\u6216\u958B\u767C\u5546\u70BA\u5927\u9678<br> \u4EE5\u4E0B\u5E7E\u7BC7\u5831\u5C0E\u53C3\u8003\uFF0C\u76EE\u524D\u4E2D\u570B\u7684\u76E3\u63A7\u4E5F\u9010\u6F38\u5C0E\u5165AI\u4EBA\u5DE5\u667A\u6167<br><a href="https://theinitium.com/article/20171218-wsj-introduction/" target="_blank" rel="noopener noreferrer">\u83EF\u723E\u8857\u65E5\u5831\u5C0E\u8B80\uFF1A\u4EBA\u5DE5\u667A\u80FD\u6642\u4EE3\u7684\u4E2D\u570B\u5F0F\u76E3\u63A7</a><br><a href="https://technews.tw/2017/11/26/backing-big-brother-chinese-facial-recognition-firms-appeal-to-funds/" target="_blank" rel="noopener noreferrer">\u300C\u8001\u5927\u54E5\u6B63\u5728\u770B\u8457\u4F60\u300D\uFF0C\u4E2D\u570B\u76E3\u8996\u7522\u696D\u7121\u6240\u4E0D\u5728</a><br><a href="https://www.bnext.com.tw/article/48550/china-guiyang-using-facial-recognition-to-arrest-criminals" target="_blank" rel="noopener noreferrer">\u76E3\u8996\u5668\u7D50\u5408\u4EBA\u81C9\u8FA8\u8B58\u5F8C\uFF0C\u4E2D\u570B\u8CB4\u967D\u5E02\u4E0A\u767E\u6436\u6848\u964D\u81F30.5\u8D77 </a><br> \u9019\u4E9B\u5831\u5C0E\uFF0C\u770B\u5B8C\u6703\u89BA\u5F97\u4F7F\u7528\u5927\u9678\u76843C\u7522\u54C1\u90FD\u6703\u6015\u6015\u7684</p><p>4.\u5E0C\u671B\u4E0D\u8981\u8DDF\u5225\u4EBA\u4E00\u6A23<br> \u81EA\u5F9E\u53BB\u5E74iPhoneX\u4E0A\u5E02\u5F8C\uFF0C\u667A\u6167\u578B\u624B\u6A5F\u5439\u8D77\u700F\u6D77\u98A8<br> \u6211\u4E0D\u592A\u559C\u89C0\u8DDF\u5225\u4EBA\u7528\u4E00\u6A23\u7684\u6771\u897F\uFF0C\u5E0C\u671B\u53EF\u4EE5\u7279\u5225\u4E00\u9EDE</p><p>\u6263\u9664\u5927\u9678\u54C1\u724C\uFF0C\u76EE\u524D\u9084\u6709\u92C1\u5408\u91D1\u7684\u624B\u6A5F<br> \u6700\u5F8C\u770B\u4E0ANokia6.1\uFF0C\u5F88\u7B26\u5408\u4EE5\u4E0A\u7684\u9700\u6C42<br> Nokia\u91CD\u8FD4\u667A\u6167\u578B\u624B\u6A5F\u5E02\u5834\uFF0C\u5C31\u662FNokia6\u6253\u982D\u9663<br> \u4ECA\u5E742018\u6709\u6539\u7248\uFF0C\u4E26\u52A0\u5165Android One\u4F5C\u696D\u7CFB\u7D71<br> \u96D6\u7136\u7DB2\u8DEF\u4E0A\u8A55\u6BD4\uFF0CNokia\u7684\u624B\u6A5F\u62CD\u7167\u5F88\u6158\u70C8<br> \u4F46\u62CD\u7167\u6211\u6703\u4EE5\u76F8\u6A5F\u70BA\u4E3B\uFF0C\u624B\u6A5F\u53EF\u80FD\u53EA\u662F\u65B9\u4FBF\u8F14\u52A9<br> \u53E6\u5916\u4E5F\u6709Google Camera HDR+\u53EF\u4EE5\u88DC\u5F37<br><img src="https://images.ctfassets.net/wcfotm6rrl7u/pvvbgqvMR2o4AyQUeOkeG/8d3fa28c8d7451ce764954516034f840/TheNewNokia6_hero-phone-optimised.png" alt=""></p><p>\u76EE\u524DNokia 6.1\u6709\u5169\u7A2E\u984F\u8272\uFF0C\u9ED1\u8272\u8207\u767D\u8272<br> \u64D4\u5FC3\u6709\u9078\u8272\u969C\u7919\uFF0C\u60F3\u4E86\u60F3\uFF0C\u9019\u4E00\u5E74\u4F86\u5E38\u7528\u767D\u8272\u8033\u6A5F<br> \u5C31\u6C7A\u5B9A\u662F\u767D\u8272\u9020\u578B\uFF0C\u7DB2\u8DEF\u4E0A\u627E\u4E86ePrice\u6BD4\u50F9\u7DB2\u9019\u500B\u7DB2\u7AD9<br> \u7DB2\u8DEF\u4E0A\u5F88\u65B9\u4FBF\uFF0C\u5F88\u591A\u8CC7\u8A0A\u53EF\u4EE5\u67E5\u5F97\u5230\uFF0C\u9078\u4E86\u5C31\u8FD1\u7684\u901A\u8A0A\u884C<br> \u5F8C\u4F86\u5C31\u7DB2\u8DEF\u4E0A\u9810\u5B9A\uFF0C\u9694\u5E7E\u5929\u53D6\u8CA8\uFF0C\u9806\u4FBF\u52A0\u8CFC\u7A7A\u58D3\u6BBC\u548C\u4FDD\u8B77\u8CBC<br> Nokia\u7684\u624B\u6A5F\u90FD\u6C92\u6709\u8033\u6A5F\uFF0C\u4E5F\u9806\u4FBF\u53BB\u8CB7\u4E86<span style="color:red;">&quot;\u767D\u8272&quot;</span>\u8033\u6A5F<br> \u6240\u4EE5\u6574\u500B\u8CB7\u5B8C<span style="color:blue;"> \u624B\u6A5F+\u7A7A\u58D3\u6BBC+\u4FDD\u8B77\u8CBC+\u8033\u6A5F =&gt; 7500\u5DE6\u53F3</span><br> \u8D95\u5728\u820A\u624B\u6A5F(M8)\u9084\u6C92\u6574\u500B\u639B\u6389\u524D\u8FA6\u5B8C\uFF0C\u7528\u4E86\u5E7E\u5929\u89BA\u5F97\u64CD\u4F5C\u883B\u9806\u7684<br><span style="color:red;">\u76EE\u524D\u64CD\u4F5C\u4F7F\u7528\u4E0A\u9664\u4E86\u5C11\u4E86\u63D0\u793A\u71C8\uFF0C\u6709\u8A0A\u606F\u4E0D\u6703\u9583\u71C8\u63D0\u793A\u5916<br> \u5176\u4ED6\u96FB\u91CF\u3001\u62CD\u7167\uFF0C\u90FD\u8DB3\u5920\u61C9\u4ED8\u65E5\u5E38\u4E0A\u7684\u4F7F\u7528</span><br><span style="color:blue;">\u624B\u6A5F\u6709\u652F\u63F4NFC\u548CVoWifi\u53CA\u96D94G\u898F\u683C</span>\uFF0C\u4E0D\u904E\u9019\u500B\u76EE\u524D\u6211\u7528\u4E0D\u5230<br> \u6709\u53EF\u80FD\u662F\u5FC3\u7406\u4F5C\u7528\u52A0\u65B0\u8033\u6A5F\uFF0C\u89BA\u5F97\u97F3\u6A02\u53EF\u4EE5\u6E05\u695A\u807D\u5230\u4E0D\u540C\u7684\u6A02\u5668<br> \u62CD\u7167\u7684\u64CD\u4F5C\u89BA\u5F97\u6C92\u6709\u6BD4\u524D\u4E00\u96BBM8\u597D\u7528\uFF0C\u8272\u8ABF\u8DDF\u60F3\u50CF\u4E2D\u6709\u843D\u5DEE<br> (\u539F\u672C\u89BA\u5F97\u7167\u7247\u7684\u8ABF\u6559\uFF0C\u984F\u8272\u5448\u73FE\u61C9\u8A72\u6703\u66F4\u9BAE\u8C54\u3001\u66F4\u597D\u770B)<br> \u4E0D\u904E\u6709\u9EDE\u53EF\u60DC\uFF0CNokia6\u662F\u96D9\u5587\u53ED\uFF0C6.1\u8B8A\u6210\u55AE\u5587\u53ED<br> \u97F3\u91CF\u8DDFM8\u6BD4\u8D77\u4F86\u6709\u5DEE\uFF0C\u4E0D\u904E\u5E73\u5E38\u5F88\u5C11\u76F4\u63A5\u64A5\u653E\u4E5F\u6C92\u5DEE<br> \u7D14\u6DE8\u7684Android One\u4F5C\u696D\u7CFB\u7D71\uFF0C\u652F\u63F4\u5169\u5E74Google\u6700\u65B0\u7248\u672COS\u66F4\u65B0<br> \u4EE5\u552E\u50F9\u8DDF\u898F\u683C\u770B\u8D77\u4F86\uFF0CNokia6.1\u5C0D\u5F97\u8D77\u5B83\u7684\u50F9\u683C<br> \u5E0C\u671BNokia6.1\u53EF\u4EE5\u627F\u63A5HTC One M8\u7684\u68D2\u5B50\uFF0C\u518D\u62303\u5E74</p><p>\u4EE5\u4E0B\u70BA\u624B\u6A5F\u898F\u683C</p><table><thead><tr><th>\u898F\u683C</th><th>\u63CF\u8FF0</th></tr></thead><tbody><tr><td>\u4F5C\u696D\u7CFB\u7D71</td><td>Android Oreo</td></tr><tr><td>CPU</td><td>Qualcomm\xAE Snapdragon\u2122 630 \u516B\u6838\u5FC3\uFF0C2.2 GHz</td></tr><tr><td>\u5167\u5EFA\u5132\u5B58\u7A7A\u9593</td><td>64 GB1 eMMC 5.1</td></tr><tr><td>\u63A5\u982D</td><td>3.5mm \u8033\u6A5F\u63D2\u5B54</td></tr><tr><td>\u5C3A\u5BF8\u548C\u985E\u578B</td><td>5.5\u201DIPS LCD full HD</td></tr><tr><td>\u4E3B\u93E1\u982D</td><td>1,600 \u842C\u756B\u7D20</td></tr><tr><td>\u524D\u93E1\u982D</td><td>800 \u842C\u756B\u7D20\uFF0C\u6700\u5927\u5EE3\u89D2\u89D2\u5EA6 84\u02DA</td></tr><tr><td>\u50B3\u8F38\u7DDA\u985E\u578B</td><td>USB Type-C (USB 2.0)</td></tr><tr><td>\u96FB\u6C60\u985E\u578B</td><td>3000 mAh \u96FB\u6C60\uFF08\u4E0D\u53EF\u62C6\u5378\uFF09</td></tr></tbody></table><p><img src="https://images.ctfassets.net/wcfotm6rrl7u/5fa7V99jEWYy2cqKIUkkuO/f9b82f7ebb0991b8e55c35ae987c50eb/TheNewNokia6_07_camera-phone-02_2x.png" alt=""></p><p>\u9019\u662F\u7528\u65B0\u624B\u6A5F\u7B2C\u4E00\u6B21\u8A66\u62CD\uFF0C\u525B\u597D\u5929\u7A7A\u662F\u9AD8\u7A7A\u5377\u96F2<br> \u6211\u559C\u6B61\u9019\u6A23\u5B50\u5929\u7A7A\u7684\u666F\u8272\uFF0C\u7C89\u6DFA\u85CD\u767D\u96F2\u5F69<br> \u89BA\u5F97\u8272\u8ABF\u9084\u883B\u4E0D\u932F\u7684\uFF0C\u5411\u7D93\u5178Nokia\u81F4\u656C<br><img src="https://farm1.staticflickr.com/877/41756481504_7e5ce573a7_k.jpg" alt=""></p><p>\u9019\u4E00\u5F35\u662F\u88DD\u4E86Google Camera\u8A66\u62CD\u7684<br> \u65E5\u51FA\u7684\u967D\u5149\u7167\u5728\u8857\u9053\u4E0A\uFF0C\u5448\u73FE\u591A\u5C64\u6B21\u8272\u5F69<br> \u5F88\u5438\u5F15\u4EBA\u6CE8\u76EE\uFF0C\u4E0D\u7981\u90FD\u60F3\u591A\u770B\u500B\u5E7E\u773C<br> \u4EBA\u751F\u5982\u6B64\uFF0C\u592B\u5FA9\u4F55\u6C42\uFF1F<br> \u5E0C\u671B\u80FD\u628A\u6BCF\u5F35\u7167\u7247\u62CD\u7684\u9019\u9EBC\u6F02\u4EAE<br> Google Camera\u679C\u7136\u540D\u4E0D\u865B\u50B3\uFF0C\u4F4E\u5149\u6E90\u90FD\u80FD\u62CD<br> \u53EF\u662F\u6A94\u6848\u8D85\u5927\uFF0C12MB\u5DE6\u53F3\uFF0C\u53EF\u80FD\u7D93\u8A08\u7B97\u7684\u95DC\u4FC2<br><img src="https://farm1.staticflickr.com/874/28598029828_a730537166_k.jpg" alt=""></p>',15),b=[i];function n(p,s,c,d,_,l){return e(),r("div",null,b)}var f=t(o,[["render",n]]);export{m as __pageData,f as default};
